import { GoogleGenAI, Type } from "@google/genai";
import { ProjectState, ExtractedDPR, ExtractedBill, BOQItem, AiSuggestion } from "../types";

const getAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error("API_KEY is not defined in the environment.");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

export const generateProjectInsights = async (projectData: ProjectState): Promise<string> => {
  const ai = getAIClient();
  if (!ai) return "API Key missing. Cannot generate insights.";

  const prompt = `
    Analyze the following construction project data and provide a concise executive summary and risk assessment.

    Project Name: ${projectData.name}
    Contract Value: ${projectData.contractValue}

    BOQ Summary (Top 3 items):
    ${projectData.boq.slice(0, 3).map(i => `- ${i.description}: ${i.executedQty}/${i.plannedQty} ${i.unit}`).join('\n')}

    Financials:
    - Bills: ${projectData.bills.length} records
    - Liabilities: ${projectData.liabilities.length} records showing pending payments and retentions.

    Please provide:
    1. Overall Health Score (0-100%)
    2. Key Financial Risks (focus on retention and unbilled liabilities)
    3. Progress Bottlenecks based on BOQ execution vs Plan.
    4. A strategic recommendation for the Project Manager.

    Keep it professional, concise, and formatted in Markdown.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "No insights generated.";
  } catch (error) {
    console.error("Error generating insights:", error);
    return "Failed to generate insights. Please check API configuration.";
  }
};

/**
 * Deep Analysis of a Document to find actionable updates
 */
export const analyzeDocumentContent = async (
  docName: string, 
  category: string,
  boqItems: BOQItem[]
): Promise<AiSuggestion[]> => {
  const ai = getAIClient();
  if (!ai) return [];

  const prompt = `
    You are an AI Site Engineer. Analyze the document named "${docName}" (Category: ${category}).
    Based on the file name and category, simulate what data would be inside and suggest 1-2 structured updates for the construction system.

    Available BOQ Items to link:
    ${boqItems.map(b => `- ID: ${b.id}, Desc: ${b.description}`).join('\n')}

    Rules:
    1. If category is "REPORT", look for quantities to update in the BOQ.
    2. If category is "BILL", look for financial amounts and vendor/client names.
    3. If there is a risk mentioned (simulated), create a RISK_ALERT.

    Return a JSON array of suggestions.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING, description: 'QUANTITY_UPDATE, BILL_DETECTION, or RISK_ALERT' },
              title: { type: Type.STRING },
              description: { type: Type.STRING },
              value: { type: Type.NUMBER, description: 'The suggested quantity or amount' },
              linkedId: { type: Type.STRING, description: 'BOQ Item ID if applicable' }
            },
            required: ["type", "title", "description"]
          }
        }
      }
    });

    const results = JSON.parse(response.text || "[]");
    return results.map((r: any) => ({
      ...r,
      id: `SUG-${Date.now()}-${Math.random().toString(36).substr(2, 4)}`,
      status: 'PENDING'
    }));
  } catch (error) {
    console.error("Deep analysis error:", error);
    return [];
  }
};

export const suggestPlannedUnitCost = async (
  description: string,
  unit: string,
  existingBOQ: BOQItem[]
): Promise<number | null> => {
  const ai = getAIClient();
  if (!ai) return null;

  const prompt = `
    Based on the following existing BOQ items in a construction project, suggest a realistic "Planned Unit Cost" (internal budgeted cost) for a new item.

    New Item Description: "${description}"
    New Item Unit: "${unit}"

    Existing Items (for context):
    ${existingBOQ.slice(0, 15).map(item => `- ${item.description} (${item.unit}): Planned Cost ৳${item.plannedUnitCost}, Selling Rate ৳${item.rate}`).join('\n')}

    Return ONLY a JSON object with a single field "suggestedCost" (number). 
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suggestedCost: { type: Type.NUMBER }
          },
          required: ["suggestedCost"]
        }
      }
    });

    const data = JSON.parse(response.text || "{}");
    return data.suggestedCost || null;
  } catch (error) {
    console.error("Cost Suggestion error:", error);
    return null;
  }
};

import React, { useState } from 'react';
import { ProjectDocument, DocumentCategory, ModuleType, BOQItem } from '../types';
import { 
  FileText, 
  Image, 
  File, 
  Search, 
  UploadCloud, 
  Download, 
  X,
  FileSpreadsheet,
  Paperclip,
  Loader2,
  CheckCircle2,
  Sparkles,
  Zap
} from 'lucide-react';
import { analyzeDocumentContent } from '../services/geminiService';

interface DocumentManagerProps {
  documents: ProjectDocument[];
  onAddDocument: (doc: ProjectDocument) => void;
  onAnalyzeDocument?: (docId: string, suggestions: any[]) => void;
  boqItems?: BOQItem[];
  filterModule?: ModuleType; 
  compact?: boolean; 
  allowUpload?: boolean;
}

const DocumentManager: React.FC<DocumentManagerProps> = ({ 
  documents, 
  onAddDocument, 
  onAnalyzeDocument,
  boqItems = [],
  filterModule,
  compact = false,
  allowUpload = true
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<DocumentCategory | 'ALL'>('ALL');
  const [selectedModule, setSelectedModule] = useState<ModuleType | 'ALL'>('ALL');
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');
  const [isUploadModalOpen, setIsUploadModalOpen] = useState(false);
  const [analyzingDocId, setAnalyzingDocId] = useState<string | null>(null);

  // Upload Form State
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [newDocName, setNewDocName] = useState('');
  const [newDocType, setNewDocType] = useState('PDF');
  const [newDocCategory, setNewDocCategory] = useState<DocumentCategory>('REPORT');
  const [newDocModule, setNewDocModule] = useState<ModuleType>(filterModule || 'GENERAL');
  const [isUploading, setIsUploading] = useState(false);

  const filteredDocs = documents.filter(doc => {
    const matchesSearch = doc.name.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'ALL' || doc.category === selectedCategory;
    const matchesModule = filterModule 
      ? doc.module === filterModule 
      : (selectedModule === 'ALL' || doc.module === selectedModule);

    const matchesDate = (!dateFrom || doc.uploadDate >= dateFrom) && 
                        (!dateTo || doc.uploadDate <= dateTo);

    return matchesSearch && matchesCategory && matchesModule && matchesDate;
  });

  const handleDeepScan = async (doc: ProjectDocument) => {
    if (!onAnalyzeDocument) return;
    setAnalyzingDocId(doc.id);
    const suggestions = await analyzeDocumentContent(doc.name, doc.category, boqItems);
    onAnalyzeDocument(doc.id, suggestions);
    setAnalyzingDocId(null);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedFile(file);
      setNewDocName(file.name);

      const ext = file.name.split('.').pop()?.toLowerCase();
      if (ext === 'pdf') setNewDocType('PDF');
      else if (['jpg', 'jpeg', 'png', 'gif'].includes(ext || '')) setNewDocType('JPG');
      else if (['xlsx', 'xls', 'csv'].includes(ext || '')) setNewDocType('XLSX');
      else if (['dwg', 'dxf'].includes(ext || '')) setNewDocType('DWG');
      else setNewDocType('PDF');
    }
  };

  const handleUpload = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsUploading(true);
    await new Promise(resolve => setTimeout(resolve, 1500));

    let fileSize = '0.0 MB';
    let fileUrl = undefined;

    if (selectedFile) {
      fileSize = `${(selectedFile.size / (1024 * 1024)).toFixed(2)} MB`;
      fileUrl = URL.createObjectURL(selectedFile);
    } else {
      fileSize = `${(Math.random() * 5 + 0.5).toFixed(1)} MB`;
    }

    const newDoc: ProjectDocument = {
      id: `D${Date.now()}`,
      name: newDocName,
      type: newDocType,
      category: newDocCategory,
      module: newDocModule,
      uploadDate: new Date().toISOString().split('T')[0],
      size: fileSize,
      url: fileUrl,
      isAnalyzed: false
    };

    onAddDocument(newDoc);
    setIsUploading(false);
    setIsUploadModalOpen(false);
    setNewDocName('');
    setSelectedFile(null);
  };

  const getIcon = (type: string) => {
    if (type.includes('PDF')) return <FileText className="w-5 h-5 text-red-500" />;
    if (type.includes('JPG') || type.includes('PNG')) return <Image className="w-5 h-5 text-blue-500" />;
    if (type.includes('XLS')) return <FileSpreadsheet className="w-5 h-5 text-green-600" />;
    if (type.includes('DWG')) return <Paperclip className="w-5 h-5 text-slate-500" />;
    return <File className="w-5 h-5 text-slate-400" />;
  };

  return (
    <div className={`bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden ${compact ? '' : 'h-full flex flex-col'}`}>
      <div className="px-6 py-4 border-b border-slate-200 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h3 className="font-semibold text-slate-800">
            {compact ? 'Related Documents' : 'Document Management'}
          </h3>
          {!compact && <p className="text-sm text-slate-500">Central repository for all project files</p>}
        </div>
        {allowUpload && (
          <button 
            onClick={() => setIsUploadModalOpen(true)}
            className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors shadow-sm text-sm"
          >
            <UploadCloud className="w-4 h-4" />
            Upload Document
          </button>
        )}
      </div>

      <div className="px-6 py-3 bg-slate-50 border-b border-slate-200 flex flex-col gap-3">
        <div className="relative w-full">
          <Search className="w-4 h-4 absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" />
          <input 
            type="text" 
            placeholder="Search documents by name..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-9 pr-4 py-2 text-sm border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
