                </h3>
                <div className="prose prose-indigo max-w-none text-slate-700 whitespace-pre-wrap text-sm leading-relaxed">
                    <ReactMarkdown>{insight}</ReactMarkdown>
                </div>
                </div>
            )}
        </div>

        {/* AI Action Sidebar */}
