import { GoogleGenAI, Type } from "@google/genai";
import { ProjectState, ExtractedDPR, ExtractedBill, BOQItem, AiSuggestion, CostBreakdown, DocumentCategory, ModuleType } from "../types";

// Always use new GoogleGenAI({ apiKey: process.env.API_KEY }) inside functions for fresh instance
export const generateProjectInsights = async (projectData: ProjectState): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Analyze the following construction project data and provide a concise executive summary and risk assessment.

    Project Name: ${projectData.name}
    Contract Value: ${projectData.contractValue}

    BOQ Summary (Top 3 items):
    ${projectData.boq.slice(0, 3).map(i => `- ${i.description}: ${i.executedQty}/${i.plannedQty} ${i.unit}`).join('\n')}

    Financials:
    - Bills: ${projectData.bills.length} records
    - Liabilities: ${projectData.liabilities.length} records showing pending payments and retentions.

    Please provide:
    1. Overall Health Score (0-100%)
    2. Key Financial Risks (focus on retention and unbilled liabilities)
    3. Progress Bottlenecks based on BOQ execution vs Plan.
    4. A strategic recommendation for the Project Manager.

    Keep it professional, concise, and formatted in Markdown.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "No insights generated.";
  } catch (error) {
    console.error("Error generating insights:", error);
    return "Failed to generate insights. Please check API configuration.";
  }
};

/**
 * AI logic to parse a BOQ Document and extract line items
 */
export const parseBoqDocument = async (docName: string): Promise<Partial<BOQItem>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    You are a quantity surveyor AI. Analyze the construction contract document named: "${docName}".
    Simulate the extraction of a Bill of Quantities (BOQ) table from this document.

    Extract at least 5-8 logical construction items that would typically appear in such a project.
    For each item, provide:
    - A unique ID (e.g., 10.10, 20.20)
    - Detailed description
    - Unit (choose from SQM, CUM, KG, NOS, RMT, CFT)
    - Quoted Selling Rate (Number)
    - Total Planned Quantity (Number)

    Return a JSON array of items.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              description: { type: Type.STRING },
              unit: { type: Type.STRING },
              rate: { type: Type.NUMBER },
              plannedQty: { type: Type.NUMBER }
            },
            required: ["id", "description", "unit", "rate", "plannedQty"]
          }
        }
      }
    });

    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("BOQ Parsing error:", error);
    return [];
  }
};

/**
 * Deep Analysis of a Document to find actionable updates
 */
export const analyzeDocumentContent = async (
  docName: string, 
  category: string,
  boqItems: BOQItem[]
): Promise<AiSuggestion[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    You are an AI Site Engineer. Analyze the document named "${docName}" (Category: ${category}).
    Based on the file name and category, simulate what data would be inside and suggest 1-2 structured updates for the construction system.

    Available BOQ Items to link:
    ${boqItems.map(b => `- ID: ${b.id}, Desc: ${b.description}`).join('\n')}

    Rules:
    1. If category is "REPORT", look for quantities to update in the BOQ.
    2. If category is "BILL", look for financial amounts and vendor/client names.
    3. If there is a risk mentioned (simulated), create a RISK_ALERT.

    Return a JSON array of suggestions.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING, description: 'QUANTITY_UPDATE, BILL_DETECTION, or RISK_ALERT' },
              title: { type: Type.STRING },
              description: { type: Type.STRING },
              value: { type: Type.NUMBER, description: 'The suggested quantity or amount' },
              linkedId: { type: Type.STRING, description: 'BOQ Item ID if applicable' }
            },
            required: ["type", "title", "description"]
          }
        }
      }
    });

    const results = JSON.parse(response.text || "[]");
    return results.map((r: any) => ({
      ...r,
      id: `SUG-${Date.now()}-${Math.random().toString(36).substr(2, 4)}`,
      status: 'PENDING'
    }));
  } catch (error) {
    console.error("Deep analysis error:", error);
    return [];
  }
};

/**
 * AI logic to suggest planned unit cost and logical breakdown
 */
export const suggestPlannedUnitCost = async (
  description: string,
  unit: string,
  existingBOQ: BOQItem[]
): Promise<{ total: number; breakdown: CostBreakdown } | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Based on the following existing BOQ items in a construction project, suggest a realistic "Planned Unit Cost" (internal budgeted cost) and its breakdown for a new item.

    New Item Description: "${description}"
    New Item Unit: "${unit}"

    Existing Items (for context and price benchmarking):
    ${existingBOQ.slice(0, 15).map(item => `- ${item.description} (${item.unit}): Planned Cost ৳${item.plannedUnitCost}`).join('\n')}

    Return a JSON object with:
    1. "total": The total estimated internal budgeted unit cost.
    2. "breakdown": { "material": number, "labor": number, "equipment": number, "overhead": number }
    The sum of breakdown components must equal the total.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
